INSERT INTO `actualites` (`id`, `titre`, `resume`, `description`, `langue_id`, `vignette`, `actualitetype_id`, `dateactualite`, `pays_id`, `spotlight`, `etat`, `created_at`, `updated_at`) VALUES
(1, 'Comment le CIJES révolutionne l’incubation des startups au Togo ?', 'Découvrez le modèle unique du CIJET qui allie technologie, accompagnement personnalisé et financement pour booster l’entrepreneuriat togolais.', '<p>L’incubation traditionnelle connaît une transformation majeure avec l’arrivée du CIJET. Plus qu’un simple incubateur, le CIJET propose un écosystème complet où l’innovation rencontre le financement et la technologie. À travers ses <strong>crédits d’incubation</strong>, ses <strong>bons d’accompagnement intelligents</strong> et son <strong>plateau digital interactif</strong>, il offre aux startups togolaises des outils inédits pour structurer leurs projets et accéder aux marchés.</p>', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 'actualites/1769785195_capture_d_ecran_2026-01-30_145923.png', 1, '2025-07-25', '3c4fbe39-dfa8-43c0-b7fd-bb946236543d', 0, 1, '2025-07-25 07:48:03', '2026-01-30 14:59:55'),
(2, '5 astuces pour rendre votre business plan irrésistible', 'Un business plan solide peut séduire investisseurs et partenaires. Voici 5 conseils pratiques pour le rendre convaincant et attractif.', '<p>Le business plan est la carte d’identité de votre projet. Mal rédigé, il peut fermer des portes ; bien structuré, il devient votre meilleur atout pour convaincre investisseurs et bailleurs. Dans cet article, nous vous dévoilons <strong>5 astuces incontournables</strong> pour concevoir un business plan clair, réaliste et séduisant, en mettant l’accent sur la viabilité financière et la stratégie de croissance.</p>', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 'actualites/1769785279_capture_d_ecran_2026-01-30_150058.png', 3, '2025-07-25', '3c4fbe39-dfa8-43c0-b7fd-bb946236543d', 0, 1, '2025-07-25 07:58:41', '2026-01-30 15:01:19'),
(3, 'Success Story : De l’idée au marché grâce au CIJES', 'Découvrez comment un jeune entrepreneur a transformé une simple idée en une entreprise prospère grâce à l’accompagnement CIJES.', '<p>Chez CIJET, nous croyons que chaque idée mérite une chance. Cette success story raconte le parcours inspirant d’un incubé qui, grâce à notre <strong>parcours structuré</strong>, nos <strong>experts mentors</strong> et nos <strong>bons d’accompagnement</strong>, a franchi toutes les étapes : de la validation du concept jusqu’à la conquête du marché. Une preuve concrète que l’innovation, soutenue par un accompagnement efficace, peut changer des vies.</p>', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 'actualites/1769785370_capture_d_ecran_2026-01-30_150233.png', 2, '2025-07-24', '3c4fbe39-dfa8-43c0-b7fd-bb946236543d', 0, 1, '2025-07-25 08:02:01', '2026-01-30 15:02:50');
