INSERT INTO `diagnosticreponses` (`id`, `titre`, `explication`, `position`, `score`, `langue_id`, `diagnosticquestion_id`, `spotlight`, `etat`, `created_at`, `updated_at`) VALUES
(189, 'Je n’ai jamais réellement formalisé où je veux aller avec mon entreprise', NULL, 1, 'A', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 47, 0, 1, '2026-01-12 19:57:40', '2026-01-12 19:57:40'),
(190, 'Je fonctionne surtout au jour le jour, en saisissant les opportunités au fur et à mesure', NULL, 1, 'A', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 47, 0, 1, '2026-01-12 19:57:40', '2026-01-12 19:57:40'),
(191, 'J’ai une idée générale de la direction à prendre, mais elle reste dans ma tête', NULL, 2, 'B', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 47, 0, 1, '2026-01-12 19:57:40', '2026-01-12 19:57:40'),
(192, 'La vision existe, mais elle n’est ni écrite ni partagée avec l’équipe', NULL, 2, 'B', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 47, 0, 1, '2026-01-12 19:57:40', '2026-01-12 19:57:40'),
(193, 'La vision est clairement définie et formalisée par écrit', NULL, 3, 'C', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 47, 0, 1, '2026-01-12 19:57:40', '2026-01-12 19:57:40'),
(194, 'La vision est écrite, réaliste et connue au moins des personnes clés de l’entreprise', NULL, 3, 'C', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 47, 0, 1, '2026-01-12 19:57:40', '2026-01-12 19:57:40'),
(195, 'Aucun objectif annuel n’a été défini', NULL, 1, 'A', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 48, 0, 1, '2026-01-12 19:57:40', '2026-01-12 19:57:40'),
(196, 'Je travaille sans objectifs clairs pour l’année', NULL, 1, 'A', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 48, 0, 1, '2026-01-12 19:57:40', '2026-01-12 19:57:40'),
(197, 'Des objectifs existent, mais ils sont vagues ou non chiffrés', NULL, 2, 'B', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 48, 0, 1, '2026-01-12 19:57:40', '2026-01-12 19:57:40'),
(198, 'J’ai des objectifs en tête, mais ils ne sont pas formalisés par écrit', NULL, 2, 'B', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 48, 0, 1, '2026-01-12 19:57:40', '2026-01-12 19:57:40'),
(199, 'Les objectifs annuels sont clairement définis et écrits', NULL, 3, 'C', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 48, 0, 1, '2026-01-12 19:57:40', '2026-01-12 19:57:40'),
(200, 'Les objectifs annuels servent réellement de référence pour orienter l\'activité', NULL, 3, 'C', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 48, 0, 1, '2026-01-12 19:57:40', '2026-01-12 19:57:40'),
(201, 'Je n’ai pas de plan précis et je réagis principalement aux urgences', NULL, 1, 'A', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 49, 0, 1, '2026-01-12 19:57:40', '2026-01-12 19:57:40'),
(202, 'Je sais ce qu’il faut faire, mais sans organisation structurée', NULL, 1, 'A', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 49, 0, 1, '2026-01-12 19:57:40', '2026-01-12 19:57:40'),
(203, 'J’élabore parfois un plan, mais je ne l’utilise pas de manière systématique', NULL, 2, 'B', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 49, 0, 1, '2026-01-12 19:57:40', '2026-01-12 19:57:40'),
(204, 'Certaines actions sont notées, mais sans suivi réel', NULL, 2, 'B', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 49, 0, 1, '2026-01-12 19:57:40', '2026-01-12 19:57:40'),
(205, 'Je travaille avec un plan d\'actions écrit et structuré', NULL, 3, 'C', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 49, 0, 1, '2026-01-12 19:57:40', '2026-01-12 19:57:40'),
(206, 'Mon plan d\'actions est chiffré, suivi et ajusté en fonction des résultats', NULL, 3, 'C', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 49, 0, 1, '2026-01-12 19:57:40', '2026-01-12 19:57:40'),
