(208, 'Les décisions sont souvent prises dans l\'urgence', NULL, 1, 'A', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 50, 0, 1, '2026-01-12 19:57:40', '2026-01-12 19:57:40'),
(209, 'Je discute parfois avec d’autres personnes, de manière informelle', NULL, 2, 'B', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 50, 0, 1, '2026-01-12 19:57:40', '2026-01-12 19:57:40'),
(210, 'Je m\'appuie sur mon expérience, sans cadre formel de décision', NULL, 2, 'B', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 50, 0, 1, '2026-01-12 19:57:40', '2026-01-12 19:57:40'),
