(3926, 'Les gens écoutent, mais peu de choses changent.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 869, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3927, 'Ils comprennent le message, mais l’engagement reste faible.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 869, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3928, 'Ils repartent avec une direction claire et des actions à mener.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 869, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3929, 'Ils repartent motivés, alignés et prêts à agir concrètement.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 869, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4200, 'Je lui donne la tâche à exécuter, sans autre explication.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 900, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
