(4202, 'J’explique le résultat attendu, le délai et l’impact de cette mission sur l’activité actuelle.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 900, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
