(4212, 'Je considère que c’est normal, il est payé pour ça.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 903, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4213, 'Je le félicite quand j’y pense.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 903, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4214, 'Je souligne ses progrès et je lui donne plus de responsabilités.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 903, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4215, 'Je cherche volontairement à le faire monter en compétence, même si cela signifie qu’il peut un jour me dépasser sur certains sujets.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 903, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4216, 'Les décisions sont bloquées car personne n’ose agir.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 904, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4217, 'Les décisions mineures avancent, les autres attendent.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 904, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4218, 'L’équipe avance avec prudence.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 904, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4219, 'L’équipe agit avec confiance car vous avez développé leur capacité de jugement.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 904, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4220, 'Chacun travaille de son côté.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 905, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
