(4222, 'Ils s’entraident spontanément pour atteindre les objectifs.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 905, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4223, 'Le partage de compétences est organisé et valorisé.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 905, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4224, 'La peur de l’erreur ou du reproche.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 906, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4225, 'Le salaire et la sécurité.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 906, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4226, 'La reconnaissance et le respect.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 906, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
