(4475, '\"Je change un petit détail après l\'autre et je reteste jusqu\'à ce que ça finisse par marcher.\"', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 968, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4476, 'Le soulagement. « Si ça marche, on ne touche à rien. Je ne cherche pas de problèmes là où il n\'y en a pas. »', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 969, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4477, 'L\'attente. « Je regarde ce que font les autres. Si tout le monde change sa façon de faire, je m\'adapterai aussi. »', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 969, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4478, 'Le réglage. « Je cherche toujours le petit détail pour que ce soit un peu plus rapide ou moins cher. »', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 969, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4479, 'L\'avance. « Même quand tout va bien, je cherche à tout simplifier pour passer à la vitesse supérieure. »', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 969, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4480, 'Je prends directement sans formalisation claire.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 970, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4481, 'Je prends en me disant que je régulariserai plus tard.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 970, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4482, 'Je me verse une rémunération ou une avance enregistrée.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 970, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4483, 'Les flux sont strictement encadrés ; je respecte les règles même sans contrôle extérieur.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 970, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4484, 'Les retards sont fréquents et j’en informe le client une fois le délai dépassé.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 971, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4485, 'Je fais au mieux, mais j’anticipe rarement les risques de retard.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 971, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4486, 'Si un risque apparaît, je préviens avant l’échéance et je propose une solution.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 971, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4487, 'Je planifie avec marge de sécurité, je suis l’avancement et je sécurise mes engagements avant même qu’un problème ne survienne.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 971, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4488, 'Je régularise uniquement quand je sens un risque de sanction.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 972, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4489, 'Je respecte les règles si cela ne complique pas trop ma situation.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 972, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4490, 'Je respecte mes obligations même sans pression extérieure.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 972, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4491, 'Je considère la conformité comme un levier stratégique de crédibilité et de réputation à long terme.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 972, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4492, 'Vous arrivez souvent en retard, changez d’avis fréquemment ou ne respectez pas toujours vos propres règles.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 973, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4493, 'Vous faites des efforts, mais votre niveau d’exigence varie selon votre humeur ou la pression.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 973, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4494, 'Vous appliquez à vous-même les standards que vous imposez aux autres.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 973, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4495, 'Vous donnez l’exemple en premier, même quand personne ne vous observe, et votre comportement crée naturellement la discipline autour de vous.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 973, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4496, 'Vous avez surtout éteint des urgences et répondu aux sollicitations. Vos priorités personnelles ont peu avancé.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 974, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4497, 'Vous aviez des priorités claires, mais au moins la moitié a été repoussée à cause d’imprévus.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 974, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4498, 'La majorité de vos actions importantes a été réalisée comme prévu.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 974, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4499, 'Vos créneaux stratégiques ont été protégés. Même sous pression, vous avez maintenu le cap sur ce qui fait réellement progresser l’entreprise.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 974, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4500, 'J’ai gardé l’information pour moi pour éviter les réactions ou les critiques.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 975, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4501, 'J’ai partagé une version partielle pour ne pas inquiéter inutilement.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 975, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4502, 'J’ai expliqué clairement la situation et les impacts pour que chacun comprenne le contexte.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 975, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4503, 'J’ai partagé les enjeux, les risques et les options, afin que l’équipe puisse contribuer à la solution.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 975, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4504, 'Je cherche à justifier ou à déplacer la responsabilité vers le contexte ou les autres.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 976, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4505, 'Je reconnais l’erreur, mais je passe rapidement à autre chose sans changer ma méthode.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 976, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4506, 'J’assume clairement ma responsabilité et je corrige la situation.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 976, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4507, 'J’assume publiquement, j’analyse la cause réelle et je modifie durablement mon mode de fonctionnement pour éviter la répétition.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 976, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4508, '“Il faut le relancer souvent, les délais changent.”', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 977, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4509, '“Il est sérieux, mais parfois on ne sait pas à quoi s’attendre.”', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 977, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4510, '“Quand il s’engage, en général il tient.”', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 977, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4511, '“Avec lui, c’est clair : ce qui est dit est fait. On peut travailler sereinement.”', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 977, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4512, 'Je m’engage d’abord pour conclure, puis j’ajuste si nécessaire.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 978, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4513, 'Je m’engage avec optimisme, même si la marge est faible.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 978, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4514, 'Je vérifie mes moyens avant de confirmer.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 978, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4515, 'Je sécurise mes capacités (ressources, délais, risques) avant de promettre, quitte à perdre l’opportunité.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 978, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4516, 'Je considère que l’argent est disponible et je l’utilise selon les besoins du moment.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 979, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4517, 'Je règle les urgences (salaires, dettes), puis je vois ce qu’il reste.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 979, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4518, 'Je distingue ce qui appartient au fonctionnement de l’entreprise (charges, stock, fournisseurs) de ce qui peut être utilisé librement.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 979, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4519, 'Je protège systématiquement le capital qui fait tourner l’entreprise et je ne touche qu’à la part réellement distribuable.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 979, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4520, 'Je n’ai pas de modèle clair ; nous vendons et encaissons les ventes au jour le jour sans vision de rentabilité globale.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 980, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4521, 'Le modèle est clair dans ma tête, mais il n\'est pas documenté ni partagé avec l\'équipe.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 980, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4522, 'Mon modèle est structuré (formalisé), mais il reste statique et n\'est pas remis en question.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 980, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4523, 'Mon modèle est visuel, évolutif, connu de l’équipe et réévalué régulièrement selon les opportunités et les menaces du marché.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 980, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4524, 'Je me concentre uniquement sur la survie immédiate et les tâches opérationnelles.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 981, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4525, 'J\'ai des objectifs à court terme, mais aucune vision inspirante à 5 ou 10 ans.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 981, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4526, 'La vision est définie par écrit, mais elle n\'est pas utilisée comme boussole pour les décisions quotidiennes.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 981, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4527, 'La mission et la vision sont claires, écrites et servent de socle à chaque arbitrage stratégique.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 981, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4528, 'Je traite les dossiers selon l\'ordre d\'arrivée ou l\'urgence perçue.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 982, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4529, 'Je confonds souvent l\'urgence (pression externe) avec l\'importance (valeurs et buts).', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 982, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4530, 'Je distingue l\'important de l\'urgent, mais j\'ai du mal à dire \"non\" aux sollicitations sans valeur ajoutée.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 982, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4531, 'Je me focalise sur les activités à haut rendement (80/20) qui servent mes objectifs essentiels.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 982, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4532, 'Il n\'y a pas de lien formalisé entre mes idées et le travail quotidien des équipes.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 983, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4533, 'Je donne des ordres ponctuels sans que l\'équipe comprenne le plan d\'ensemble.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 983, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4534, 'J\'ai un plan d\'action annuel, mais il est trop rigide pour s\'adapter aux imprévus.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 983, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4535, 'La vision est traduite en objectifs SMART et en étapes précises avec des échéanciers partagés.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 983, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4536, 'Les ressources sont allouées en fonction des crises ou des demandes les plus fortes.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 984, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4537, 'Je garde la main sur toutes les ressources par peur de perdre le contrôle tactique.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 984, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4538, 'J\'alloue des moyens aux projets importants, mais sans critères de rentabilité ou d\'impact précis.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 984, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4539, 'J\'alloue mes ressources stratégiquement sur les leviers de profit les plus élevés.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 984, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4540, 'Je ne suis aucun indicateur de façon formelle, je pilote \"à l\'instinct\".', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 985, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4541, 'Je regarde principalement le chiffre d\'affaires et le solde bancaire en fin de mois.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 985, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4542, 'Je suis quelques indicateurs de production et financiers mensuellement.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 985, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4543, 'Je pilote avec un tableau de bord équilibré (KPIs) incluant des mesures de performance et de satisfaction client.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 985, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4544, 'Nous ne faisons pas de réunions de suivi stratégique, seulement de l\'opérationnel urgent.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 986, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4545, 'Le point est fait seulement lorsqu\'un problème grave survient.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 986, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4546, 'J\'organise des réunions mensuelles, mais elles dérivent souvent vers la résolution de problèmes techniques.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 986, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4547, 'J\'organise des revues périodiques structurées pour valider les progrès et pivoter si nécessaire.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 986, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4548, 'Mon équipe exécute des tâches sans connaître les objectifs finaux de l\'entreprise.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 987, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4549, 'J\'explique la stratégie une fois par an, lors de l\'entretien annuel.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 987, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4550, 'Les cadres connaissent les objectifs, mais les employés n\'y voient pas leur contribution directe.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 987, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4551, 'Chaque membre peut expliquer comment son travail quotidien sert la vision globale de l\'entreprise.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 987, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4552, 'Je subis les changements du marché sans les avoir anticipés.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 988, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4553, 'Je réagis aux évolutions de la concurrence après qu\'elles aient impacté mon CA.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 988, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4554, 'Je réalise des diagnostics (type SWOT) occasionnels, mais sans impact sur ma feuille de route.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 988, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4555, 'Je pratique une veille constante et j\'anticipe les tendances pour adapter mon orientation stratégique.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 988, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
