(4630, 'J\'ai conscience des risques, mais je n\'ai pas formalisé de plan de prévention contre le stress ou le harcèlement.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1007, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4631, 'J\'ai instauré une politique de \"tolérance zéro\" et je maintiens une veille constante sur la santé mentale de l\'équipe.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1007, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4632, 'Les décisions importantes sont prises seul, sans formalisme, ce qui crée des doutes chez mes partenaires.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1008, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4633, 'Je traite parfois avec des proches ou des amis sans mettre en place de règles de mise en concurrence.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1008, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4634, 'Je formalise les décisions sensibles par des Procès-Verbaux (PV) et je rends compte périodiquement à des mentors ou associés.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1008, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4635, 'L\'éthique est institutionnalisée : j\'ai mis en place des règles claires contre la corruption et l\'abus de biens sociaux.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1008, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4636, 'Toutes les règles sont dans ma tête ; rien n\'est écrit, ce qui crée du chaos en mon absence.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1009, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4637, 'Il existe quelques notes éparses, mais elles ne sont pas accessibles à tous les collaborateurs.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1009, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4638, 'J\'ai instauré des procédures simples pour les tâches critiques (facturation, accueil, sécurité).', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1009, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4639, 'L\'entreprise dispose d\'un manuel de procédures clair et traçable, garantissant une autonomie en toute conformité.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1009, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4640, 'J\'embauche uniquement dans l\'urgence quand le travail déborde et que je ne m\'en sors plus.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1100, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4641, 'Je définis les tâches à accomplir de manière floue juste au moment de rédiger l\'annonce.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1100, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4642, 'Je dispose de fiches de poste écrites qui listent les missions et les compétences pour chaque fonction.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1100, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4643, 'Ma stratégie RH est alignée sur mon business plan : j\'identifie les métiers de demain et je planifie les recrutements.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1100, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4644, 'Je recrute principalement à l\'intuition ou par recommandation, sans test ni critères précis.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1101, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4645, 'Je mène des entretiens classiques, sans grille de questions préparée ni comparaison objective.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1101, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4646, 'J\'utilise des entretiens structurés avec des questions situationnelles et des tests d\'aptitude technique.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1101, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4647, 'Mon processus est complet (marque employeur, mises en situation) et valide l\'adéquation aux valeurs.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1101, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4648, 'Le salarié est mis au travail immédiatement ; il doit \"apprendre sur le tas\".', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1102, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4649, 'Je remets un livret d\'accueil et je présente brièvement le nouvel arrivant à l\'équipe.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1102, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4650, 'Un parcours d\'intégration est défini (parrainage, formation) pour rendre le salarié opérationnel rapidement.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1102, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4651, 'Je réalise des points d\'étape formels durant la période d\'essai pour transmettre la culture d\'entreprise.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1102, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4652, 'Tout le monde est polyvalent par nécessité ; les rôles sont flous et les consignes orales.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1103, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4653, 'J\'ai un organigramme, mais il est rarement mis à jour et ne reflète pas les responsabilités réelles.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1103, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4654, 'Chaque collaborateur dispose d\'une fiche de fonction décrivant sa mission et ses rapports hiérarchiques.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1103, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4655, 'La structure est organisée par fonctions clés et non par personnalités, garantissant l\'ordre en mon absence.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1103, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4656, 'Les priorités changent chaque jour selon les urgences ou mon humeur du moment.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1104, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4657, 'Je donne des consignes globales (\"fais de ton mieux\") sans critères de mesure clairs.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1104, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4658, 'Je fixe des objectifs SMART lors de l\'entretien annuel de performance.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1104, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4659, 'Les objectifs individuels sont déclinés de la vision globale et suivis via un tableau de bord mensuel.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1104, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4660, 'Je n\'ai pas de système formel ; je ne fais de remarques que lorsque quelque chose ne va pas.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1105, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4661, 'Je réalise un entretien annuel obligatoire, mais il est vécu comme une corvée administrative sans suite.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1105, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4662, 'L\'entretien annuel est un vrai moment d\'échange sur les succès, les compétences et les besoins.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1105, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4663, 'Je pratique le feedback continu et des entretiens de mi-année pour agir comme un coach en temps réel.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1105, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4664, 'Je fais presque tout moi-même par peur que ce soit mal fait (micro-management).', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1106, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4665, 'Je confie des tâches mais je les reprends dès qu\'il y a un problème (délégation inverse).', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1106, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4666, 'Je délègue des missions entières à des personnes qualifiées avec des points de contrôle réguliers.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1106, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4667, 'Je délègue l\'autorité et la décision, me permettant de rester \"au-dessus\" pour piloter la stratégie.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1106, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4668, 'Je ne propose pas de formation ; les compétences sont figées lors de l\'embauche.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1107, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4669, 'Je forme les salariés uniquement par obligation légale ou changement d\'outil technique.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1107, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4670, 'J\'ai un plan de formation annuel lié aux lacunes identifiées lors des évaluations.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1107, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4671, 'Je favorise une culture d\'apprentissage permanent et de transmission interne pour viser l\'excellence.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1107, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4672, 'Je tolère la situation par peur du conflit ou je réagis par la colère sans méthode.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1108, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4673, 'Je multiplie les reproches informels sans jamais formaliser un plan d\'amélioration.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1108, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4674, 'Je mène des entretiens de recadrage factuels avec des délais de progression précis.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1108, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4675, 'Je diagnostique si le problème est lié à la compétence ou à la motivation, et j\'agis avec fermeté.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1108, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4676, 'L\'organisation est pyramidale et tout repose sur mes épaules ; le personnel est passif.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1109, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4677, 'La motivation de l\'équipe repose essentiellement sur la pression ou les primes financières.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1109, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4678, 'J\'encourage la prise d\'initiative et je reconnais publiquement les réussites de l\'équipe.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1109, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4679, 'J\'ai bâti une équipe autonome et responsable, alignée sur une vision commune et un plein potentiel.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1109, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4680, 'À l\'aveugle : Je ne regarde pas ce qui se passe ailleurs, je me concentre uniquement sur mes commandes actuelles.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1200, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4681, 'Au flair : Je discute avec mes clients, mais je n\'ai pas de données précises sur les nouvelles tendances.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1200, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4682, 'Vigilant : Je réalise des analyses régulières (opportunités/menaces) pour ajuster mon offre au marché.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1200, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4683, 'Anticipateur : Je pratique une veille constante pour détecter les besoins futurs avant mes concurrents.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1200, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4684, 'Par hasard : On fait la même chose que les autres, souvent en essayant d\'être moins cher.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1201, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4685, 'Par sympathie : On mise sur le bon contact, mais notre offre reste techniquement banale.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1201, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4686, 'Par la qualité : Nos produits sont meilleurs ou plus robustes que la moyenne du marché.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1201, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4687, 'Par l\'unicité : Notre positionnement est clair et tranché ; personne ne résout le problème comme nous.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1201, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4688, 'Je vends à tout le monde sans distinction ; mon offre est identique pour tous.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1202, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4689, 'Je distingue quelques types de clients, mais mon discours reste très généraliste.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1202, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4690, 'J\'utilise des critères précis (géographiques, démographiques) pour découper mon marché.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1202, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4691, 'J\'ai créé des \"Personas\" détaillés pour chaque segment, me permettant d\'adapter mon offre chirurgicalement.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1202, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4692, 'Mon produit est standard ; je mise principalement sur ma disponibilité ou ma gentillesse.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1203, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4693, 'Mon offre apporte un bénéfice clair, mais elle ressemble beaucoup à celle de mes concurrents directs.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1203, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4694, 'Ma valeur ajoutée est clairement identifiée (gain de temps, sécurité) et répond à un problème précis.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1203, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4695, 'J\'ai un positionnement \"Océan Bleu\" : mon offre est si innovante que je suis l\'acteur incontournable de ma niche.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1203, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4696, 'Je m\'aligne sur les concurrents ou j\'ajoute une petite marge sans savoir si c\'est réellement rentable.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1204, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4697, 'Je fixe mes prix en fonction de mes coûts de revient, sans analyser la psychologie du client.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1204, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4698, 'Je prends en compte trois variables : mes coûts, les prix du marché et la valeur perçue.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1204, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4699, 'J\'utilise la méthode du \"prix d\'acceptabilité\" et je connais le prix maximum lié à la valeur que je délivre.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1204, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4700, 'Je parle trop technique ou je me perds dans les détails de \"comment ça marche\".', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1205, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4701, 'Je présente mon entreprise, mon historique et mes produits de manière factuelle.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1205, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4702, 'J\'utilise des messages clés et des phrases chocs pour marquer les esprits.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1205, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4703, 'Je raconte une histoire ou je pose une question qui captive immédiatement mon auditoire.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1205, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4704, 'Je vends la même chose depuis des années, c\'est au client de s\'adapter à mon offre.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1206, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4705, 'Je modifie mon offre seulement quand je commence à perdre trop de clients.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1206, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4706, 'Je demande régulièrement des avis pour améliorer mes services existants.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1206, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4707, 'J\'utilise les retours clients pour créer de nouveaux produits \"Océan Bleu\" en rupture.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1206, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4708, 'Uniquement par le bouche-à-oreille, sans aucun contrôle de ma part.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1207, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4709, 'Un peu de réseaux sociaux, un peu de flyers, mais sans réelle cohérence.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1207, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4710, 'Mon message est identique et cohérent sur tous mes supports (site, réseaux, bureaux).', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1207, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4711, 'J\'ai un canal d\'acquisition clair qui génère des prospects de manière régulière.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1207, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4712, 'Ils exécutent des tâches sans comprendre l\'image que je veux projeter.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1208, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4713, 'Ils connaissent le logo et le slogan, mais pas forcément les valeurs profondes.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1208, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4714, 'Ils comprennent les besoins des clients et leur rôle dans leur satisfaction.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1208, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4715, 'Chaque membre incarne la vision et la différence de l\'entreprise au quotidien.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1208, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4716, 'Je bricole moi-même mes publicités ou mon site web pour économiser.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1209, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4717, 'Je valide chaque mot, mais je n\'ai pas de stratégie d\'ensemble.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1209, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4718, 'Je définis les objectifs (SMART) et je délègue la création technique.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1209, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4719, 'Je bâtis un système où l\'entreprise attire ses clients de manière autonome.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1209, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4720, 'L\'information circule par rumeur ; je ne communique que quand on me pose des questions.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1210, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4721, 'Je dis les choses quand je croise les gens, avec un risque élevé de distorsion du message.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1210, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4722, 'J\'organise des réunions fixes et formalisées pour partager les objectifs et les résultats.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1210, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4723, 'Les flux sont structurés (écrits, oraux, outils) ; chacun accède rapidement aux données pour décider.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1210, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4724, 'Je donne des ordres vagues (\"Occupe-toi de ça\") sans préciser le délai ni le résultat attendu.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1211, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4725, 'Je donne des consignes orales précises mais sans expliquer le \"Pourquoi\" (le sens).', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1211, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4726, 'Je fixe des objectifs clairs et m\'assure que la méthode est identifiée (Qui, Quoi, Où, Quand, Comment, Pourquoi).', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1211, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4727, 'Stratégique : Chaque consigne est SMART et explicitement reliée à la vision globale de l\'entreprise.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1211, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4728, 'Je ne communique que lorsqu\'un problème grave survient (mode \"pompier\").', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1212, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4729, 'Je demande des nouvelles de temps en temps, sans méthode de suivi systématique.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1212, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4730, 'J\'utilise des reportings réguliers pour suivre l\'avancement des projets et les indicateurs.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1212, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4731, 'Je pratique le briefing (cadrage) et le debriefing (bilan) pour corriger les dérives immédiatement.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1212, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4732, 'Je reste enfermé dans mon bureau ; je méconnais les préoccupations réelles de mes collaborateurs.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1213, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4733, 'Ma porte est ouverte, mais j\'attends passivement que l\'on vienne m\'informer.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1213, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4734, 'Je pratique une écoute empathique et je reformule pour valider la compréhension des besoins.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1213, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4735, 'Je circule sur le terrain pour voir, entendre et désamorcer les tensions.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1213, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4736, 'Nous n\'avons aucune politique de communication ; nous comptons sur le bouche-à-oreille passif.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1214, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4737, 'Nous communiquons sur nos produits/prix, sans identité visuelle ni message de valeur.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1214, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4738, 'Notre communication est cohérente sur tous les supports et valorise notre savoir-faire.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1214, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4739, 'Nous diffusons un discours et des valeurs qui nous distinguent radicalement de la concurrence.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1214, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4740, 'Je m\'embrouille dans les détails techniques et je perds mon auditeur.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1215, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4741, 'Je présente mes produits et mon historique de manière classique.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1215, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4742, 'J\'utilise un \"Elevator Pitch\" (moins de 2 minutes) centré sur le bénéfice client.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1215, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4743, 'Je raconte une histoire (storytelling) qui captive et donne envie de collaborer immédiatement.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1215, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4744, 'Je m\'énerve ou je coupe court à la discussion (posture explosive ou fuyante).', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1216, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4745, 'Je cherche des excuses ou je rejette la faute sur les autres (posture défensive).', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1216, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4746, 'Je prends du recul, je respire et je reste factuel pour désamorcer la tension.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1216, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4747, 'Je reste stable, j\'écoute sans interrompre et je transforme le conflit en problème à résoudre.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1216, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4748, 'Je n\'ai pas de site internet ou de page sur les RS, ou ils ne sont plus à jour depuis des années.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1217, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4749, 'J\'ai un site ou une page, mais ils ne me ramènent aucun contact et je ne surveille pas mon e-réputation.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1217, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4750, 'Mon site ou ma page est professionnel et je communique régulièrement sur les réseaux sociaux adaptés à ma cible.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1217, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4751, 'Internet est un levier d\'acquisition automatisé ; je réponds aux avis et je soigne mon image digitale quotidiennement.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1217, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4752, 'Mes actes contredisent souvent mes paroles (ex : exiger la ponctualité tout en étant en retard).', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1218, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4753, 'Je suis exemplaire quand tout va bien, mais je craque sous la pression.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1218, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4754, 'Je m\'efforce d\'être en accord avec mes valeurs et je reconnais mes erreurs quand je m\'en éloigne.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1218, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4755, 'Mes gestes, mes paroles et mes décisions sont parfaitement alignés ; mon équipe peut se fier totalement à ma parole.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1218, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4756, 'Je suis le seul à détenir l\'information ; sans moi, l\'équipe est \"aveugle\".', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1219, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4757, 'Je demande aux autres de communiquer, mais sans définir de règles de validation.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1219, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4758, 'Des règles internes claires définissent qui doit être informé de quoi et comment (ex : matrice RACI).', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1219, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4759, 'J\'ai bâti un système où chaque collaborateur est un ambassadeur formé, capable de transmettre la vision de manière autonome.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1219, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4760, 'Je vends à toute personne qui se présente, sans cible précise ni stratégie écrite.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1220, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4761, 'Je connais mes concurrents, mais mon offre ressemble à la leur ; je me bats souvent sur les prix.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1220, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4762, 'J\'ai identifié des niches spécifiques (créneaux) que je sers mieux que les gros acteurs du marché.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1220, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4763, 'Mon positionnement est unique et différencié ; mon offre répond précisément aux frustrations de mon « client idéal ».', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1220, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4764, 'Chaque vente est une improvisation ; je ne sais pas précisément où en sont mes prospects.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1221, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4765, 'Je suis mes proformas en cours, mais je n\'ai pas de vision sur les étapes de détection des clients.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1221, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4766, 'J\'utilise un « pipe commercial » pour catégoriser mes prospects et anticiper les baisses d\'activité.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1221, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4767, 'Mon tunnel de vente est une procédure répétitive générant du profit qui fonctionne avec ou sans moi.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1221, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4768, 'Je ne recontacte mes clients que s\'ils m\'appellent ou pour une commande urgente.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1222, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4769, 'J\'ai un fichier client, mais je ne l\'utilise pas pour proposer de nouvelles offres.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1222, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4770, 'J\'applique la loi de Pareto (20 % des clients font 80 % du CA) et je soigne mes clients prioritaires.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1222, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4771, 'J\'utilise un CRM pour automatiser les relances, le cross-selling et transformer mes clients en ambassadeurs.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1222, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4772, 'Je n\'ai pas d\'objectifs chiffrés ; on essaye de vendre « le plus possible ».', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1223, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4773, 'Je fixe uniquement un objectif de chiffre d\'affaires global annuel.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1223, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4774, 'Mes objectifs sont Simples, Mesurables, Ambitieux, Réalistes et Temporels (SMART).', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1223, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4775, 'Les objectifs sont déclinés par collaborateur, suivis et acceptés par l\'équipe comme un challenge.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1223, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4776, 'Je regarde seulement le solde en banque et le chiffre d\'affaires à la fin du mois.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1224, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4777, 'Je suis le montant total des devis envoyés et le nombre de rendez-vous effectués.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1224, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4778, 'Je pilote avec une dizaine de chiffres clés (taux de signature, panier moyen, délai de règlement).', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1224, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4779, 'J\'analyse les causes d\'échec des ventes perdues pour ajuster ma stratégie en temps réel.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1224, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4780, 'Je cède souvent sur le prix par peur de perdre le client ou le contrat.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1225, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4781, 'Je parle beaucoup de mon produit mais j\'écoute peu les besoins réels du prospect.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1225, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4782, 'Je cherche des solutions « Gagnant-Gagnant » en traitant les objections avec méthode (ex: SONCAS).', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1225, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4783, 'Je maîtrise ma solution de repli (MESORE) et je vends de la valeur/transformation plutôt qu\'un prix.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1225, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4784, 'On se concentre sur la vente immédiate sans se soucier de l\'image laissée au client.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1226, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4785, 'Les documents (devis, factures) sont corrects, mais l\'image de marque n\'est pas affirmée.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1226, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4786, 'Mon identité visuelle et mon discours sont harmonisés sur tous les supports.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1226, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4787, 'L\'entreprise est perçue comme un expert référent ; chaque collaborateur incarne la marque.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1226, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4788, 'Je réalise qu\'un client n\'a pas payé quand j\'ai un trou de trésorerie.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1227, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
