(4864, 'Mes chiffres sont enterrés dans la paperasse ; je ne connais ma rentabilité qu\'en fin d\'année.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1246, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4865, 'Je regarde mon chiffre d\'affaires une fois par mois, mais sans analyse détaillée.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1246, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4866, 'J\'ai des tableaux de bord (KPI) simples pour suivre mes marges et mes ventes.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1246, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4867, 'Mes données me permettent de simuler l\'avenir et d\'identifier mes meilleurs leviers de profit.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1246, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4868, 'Je n\'ai aucune vitrine numérique ; je dépends totalement de mon réseau physique.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1247, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4869, 'J\'ai une page Facebook ou un site internet que je ne mets jamais à jour (présence passive).', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1247, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4870, 'Je publie régulièrement et mon site internet me rapporte des contacts qualifiés.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1247, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4871, 'Mon système numérique attire, convertit et fidélise les clients de manière automatisée.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1247, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4872, 'Je perds tout ; mon entreprise s\'arrête instantanément (crash total).', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1248, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4873, 'J\'ai une clé USB, mais je ne l\'ai pas mise à jour depuis des mois.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1248, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4874, 'Toutes mes données sont synchronisées sur le Cloud et protégées par des mots de passe.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1248, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4875, 'J\'ai un plan de secours ; je peux redémarrer mon activité de n\'importe où en 2 heures.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1248, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4876, 'Sans moi, personne ne sait utiliser les outils ou accéder aux infos (dirigeant-centrique).', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1249, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4877, 'Quelques employés utilisent des outils, mais il n\'y a pas de règle de fonctionnement commune.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1249, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4878, 'J\'ai mis en place des guides d\'utilisation (SOP) pour nos outils numériques.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1249, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4879, 'Chaque membre est autonome grâce à la puissance du système (organisation apprenante).', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1249, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4880, 'Je traite l\'administratif seul le soir ou le week-end, négligeant ces fonctions par manque de temps.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1250, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4881, 'Les tâches sont floues et ne sont traitées que sous la pression de l\'urgence ou des pénalités.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1250, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4882, 'Le secrétariat ou l\'office management sont clairement définis et disposent d\'outils adaptés.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1250, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4883, 'Le support administratif est un levier stratégique qui fournit des rapports d\'aide à la décision.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1250, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4884, 'Les dossiers sont éparpillés entre carnets papier, fichiers isolés et ma propre mémoire (chaos documentaire).', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1251, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4885, 'J\'utilise des classeurs physiques mais sans méthode de tri rigoureuse (perte de temps en recherche).', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1251, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4886, 'Les documents sont classés par catégories et sauvegardés sur un Cloud sécurisé (Google Drive, Dropbox).', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1251, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4887, 'L\'archivage est numérisé, indexé et accessible instantanément, garantissant la conformité lors d\'un audit.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1251, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4888, 'Je découvre mes obligations lors de mises en demeure ou de retards de paiement (pilotage par la sanction).', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1252, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4889, 'Je confie tout à mon expert-comptable sans comprendre les choix fiscaux ni vérifier l\'agenda social.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1252, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4890, 'Je tiens les registres légaux à jour et je respecte scrupuleusement le calendrier des déclarations.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1252, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4891, 'Je pratique une veille réglementaire et j\'utilise la fiscalité comme un instrument de développement de mon patrimoine.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1252, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4892, 'Tout est dans ma tête ; si je m\'absente, tout s\'arrête car personne ne sait comment procéder.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1253, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4893, 'Les méthodes de travail se transmettent oralement, entraînant des erreurs répétitives et une dégradation du système.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1253, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4894, 'J\'ai rédigé des procédures standard (SOP) pour les processus critiques (accueil, facturation, livraisons).', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1253, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4895, 'La documentation permet de former une recrue instantanément et d\'assurer une qualité constante sans mon intervention.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1253, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4896, 'Aucun plan n\'existe ; un incident grave signifierait l\'arrêt définitif de l\'entreprise.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1254, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4897, 'J\'ai quelques assurances mais pas de stratégie de redémarrage rapide de l\'activité.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1254, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4898, 'J\'ai identifié des solutions alternatives (Plan B) et des fonds de secours pour les crises.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1254, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4899, 'Le système permet de redémarrer l\'activité en quelques heures, protégeant structure et revenus.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1254, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4900, 'Je ne vois pas les risques de rupture (fournisseurs, outils) avant qu\'ils ne surviennent.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1255, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4901, 'Je sais quels outils sont clés, mais je n\'ai pas formalisé de solution de repli.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1255, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4902, 'J\'ai cartographié mes interdépendances et je gère activement mes partenariats.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1255, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4903, 'L\'organisation est structurée pour ne plus dépendre exclusivement d\'un tiers ou du dirigeant.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1255, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4904, 'Je considère que les problèmes n\'arrivent qu\'aux autres ; je ne fais aucun diagnostic.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1256, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4905, 'Je n\'analyse les risques (financiers, juridiques) qu\'après avoir subi un incident.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1256, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4906, 'J\'évalue mes zones de risques et j\'intègre des points de contrôle dans mes processus.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1256, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4907, 'L\'analyse des risques est au cœur de ma stratégie pour transformer chaque vulnérabilité en sécurité.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1256, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4908, 'Je me sens \"prisonnier\" de mes prestataires et ne comprends pas leurs travaux.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1257, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4909, 'Je les sollicite au coup par coup sans contrat ni objectifs de performance clairs.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1257, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4910, 'Je travaille en collaboration étroite, vérifie leurs rapports et m\'assure de leur responsabilité.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1257, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4911, 'Je pilote mes experts avec des missions précises et les intègre à ma vision de croissance.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1257, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4912, 'Tout est dans ma tête ; le savoir se perd à chaque départ de collaborateur.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1258, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4913, 'Quelques notes de service existent mais elles sont souvent obsolètes.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1258, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4914, 'J\'ai mis en place un manuel de procédures (SOP) pour garantir la régularité du service.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1258, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4915, 'La documentation permet de former une recrue instantanément et assure une qualité constante.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1258, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4916, 'L\'entreprise est bousculée par la moindre urgence ; je navigue à vue (chaos permanent).', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1259, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4917, 'L\'ordre dépend uniquement de ma présence physique et de mon autorité directe.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1259, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4918, 'Les rôles sont clairs via un organigramme et les priorités stratégiques sont respectées.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1259, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4919, 'L\'organisation est résiliente, fonctionne en autopilote et reste alignée sur ma vision.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 1259, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25');
