INSERT INTO `faqs` (`id`, `question`, `reponse`, `langue_id`, `pays_id`, `spotlight`, `etat`, `created_at`, `updated_at`) VALUES
(1, 'Qu’est-ce que e-CIJES ?', '<p><span style=\"background-color: transparent; color: rgb(0, 0, 0);\">e-CIJES est la plateforme numérique de la CJES Togo dédiée à la structuration, l’accompagnement et la certification des entreprises de moins de 10 ans. Elle permet de diagnostiquer le niveau de maturité d’une entreprise, de générer un plan d’action personnalisé et de suivre sa progression jusqu’à l’accès aux marchés et aux financements.</span></p>', 'f9a16e49-d975-4d63-b201-5aee5888ac44', '3c4fbe39-dfa8-43c0-b7fd-bb946236543d', 0, 1, '2025-07-25 08:11:40', '2026-02-19 12:29:27'),
(2, 'À qui s’adresse la plateforme ?', '<p><span style=\"background-color: transparent; color: rgb(0, 0, 0);\">e-CIJES s’adresse aux startups, PME, coopératives, porteurs de projets et entreprises en activité depuis moins de 10 ans. </span></p><p><span style=\"background-color: transparent; color: rgb(0, 0, 0);\">Elle est également ouverte aux consultants, coachs, agences et partenaires agréés CJES intervenant dans l’accompagnement.</span></p>', 'f9a16e49-d975-4d63-b201-5aee5888ac44', '3c4fbe39-dfa8-43c0-b7fd-bb946236543d', 0, 1, '2025-07-25 08:12:40', '2026-02-19 12:30:08'),
(3, 'Comment fonctionne le diagnostic ?', '<p><span style=\"background-color: transparent; color: rgb(0, 0, 0);\">Le diagnostic est un outil digital structuré qui évalue l’entreprise sur plusieurs blocs essentiels : stratégie, finance, juridique, RH, marketing, opérations, digital, etc. </span></p><p><span style=\"background-color: transparent; color: rgb(0, 0, 0);\">À l’issue de l’évaluation, un score de maturité est généré ainsi qu’un plan d’accompagnement personnalisé.</span></p>', 'f9a16e49-d975-4d63-b201-5aee5888ac44', '3c4fbe39-dfa8-43c0-b7fd-bb946236543d', 0, 1, '2026-02-19 12:31:00', '2026-02-19 12:31:00'),
(4, 'Combien de temps dure un parcours d’accompagnement ?', '<p><span style=\"background-color: transparent; color: rgb(0, 0, 0);\">La durée dépend du niveau de maturité de l’entreprise et de son rythme d’exécution. </span></p><p><span style=\"background-color: transparent; color: rgb(0, 0, 0);\">Le parcours est progressif et basé sur des jalons validés. L’objectif est la progression mesurable, pas la durée fixe.</span></p>', 'f9a16e49-d975-4d63-b201-5aee5888ac44', '3c4fbe39-dfa8-43c0-b7fd-bb946236543d', 0, 1, '2026-02-19 12:31:30', '2026-02-19 12:31:30'),
(5, 'Que sont les badges de capacité ?', '<p><span style=\"background-color: transparent; color: rgb(0, 0, 0);\">Les badges de capacité sont des certifications digitales attestant du niveau réel de structuration de l’entreprise. </span></p><p><span style=\"background-color: transparent; color: rgb(0, 0, 0);\">Ils sont attribués après validation des livrables et peuvent faciliter l’accès aux marchés, aux financements et aux partenariats.</span></p>', 'f9a16e49-d975-4d63-b201-5aee5888ac44', '3c4fbe39-dfa8-43c0-b7fd-bb946236543d', 0, 1, '2026-02-19 12:32:13', '2026-02-19 12:32:13'),
(6, 'e-CIJES garantit elle un financement ?', '<p><span style=\"background-color: transparent; color: rgb(0, 0, 0);\">Non. La plateforme ne garantit pas automatiquement un financement. </span></p><p><span style=\"background-color: transparent; color: rgb(0, 0, 0);\">En revanche, elle prépare et structure l’entreprise pour améliorer significativement ses chances d’accès aux marchés et aux financements.</span></p>', 'f9a16e49-d975-4d63-b201-5aee5888ac44', '3c4fbe39-dfa8-43c0-b7fd-bb946236543d', 0, 1, '2026-02-19 12:33:15', '2026-02-19 12:33:15'),
(7, 'e-CIJES garantit elle les marchés ?', '<p>Non. La plateforme e-CIJES ne garantit pas l\'accès automatique aux marchés. En revanche, elle met en place un parcours structurant qui maximise les chances des PME d\'y accéder.</p><p><br></p><p>Voici concrètement comment e-CIJES prépare les entreprises à décrocher des marchés :</p><p><br></p><p><strong> a. Diagnostic personnalisé</strong></p><p>Dès l\'inscription, un diagnostic est réalisé pour identifier les forces et les lacunes de l\'entreprise dans différents domaines (gestion, conformité, marketing, etc.).</p><p><br></p><p><strong>b. Orientation vers la CJES Academy</strong></p><p>Sur la base du diagnostic, l\'entrepreneur est orienté vers des formations ciblées sur la CJES Academy pour renforcer ses compétences dans les domaines spécifiques où des progrès sont nécessaires.</p><p><br></p><p><strong>c. Accompagnement par des experts</strong></p><p>La plateforme met en relation l\'entrepreneur avec un réseau de mentors, coachs et conseillers qui l\'accompagnent tout au long de son parcours de maturation.</p><p><br></p><p><strong>d. Obtention de badges de compétences</strong></p><p>Au fur et à mesure que l\'entrepreneur suit les formations et valide les étapes clés, il obtient des badges numériques attestant de sa progression et de sa maîtrise de compétences spécifiques.</p><p><br></p><p><strong>e. Accès facilité au CJES HUB</strong></p><p>Ces badges constituent un véritable passeport pour les marchés : ils permettent à l\'entrepreneur d\'accéder à la CJES HUB, une plateforme dédiée où sont publiées des opportunités d\'affaires, des appels d\'offres et des mises en relation avec des acheteurs.</p><p><br></p>', 'f9a16e49-d975-4d63-b201-5aee5888ac44', '3c4fbe39-dfa8-43c0-b7fd-bb946236543d', 0, 1, '2026-02-19 13:15:49', '2026-02-19 13:17:31'),
(8, 'Quelle est la différence entre e-CIJES et un incubateur classique ?', '<p><span style=\"background-color: transparent; color: rgb(0, 0, 0);\">e-CIJES est une plateforme structurante et traçable basée sur des référentiels normés, des indicateurs mesurables et des certifications progressives. </span></p><p><span style=\"background-color: transparent; color: rgb(0, 0, 0);\">Elle ne se limite pas à du mentorat ponctuel : elle industrialise l’accompagnement.</span></p>', 'f9a16e49-d975-4d63-b201-5aee5888ac44', '3c4fbe39-dfa8-43c0-b7fd-bb946236543d', 0, 1, '2026-02-19 13:18:18', '2026-02-19 13:18:18'),
(9, 'Les données de mon entreprise sont-elles sécurisées ?', '<p><span style=\"background-color: transparent; color: rgb(0, 0, 0);\">Oui. Les informations partagées sur la plateforme sont confidentielles et utilisées uniquement dans le cadre de l’accompagnement et du suivi structuré.</span></p>', 'f9a16e49-d975-4d63-b201-5aee5888ac44', '3c4fbe39-dfa8-43c0-b7fd-bb946236543d', 0, 1, '2026-02-19 13:18:49', '2026-02-19 13:18:49'),
(10, 'Est-ce gratuit ?', '<p><span style=\"background-color: transparent; color: rgb(0, 0, 0);\">Certaines fonctionnalités de base peuvent être accessibles gratuitement. </span></p><p><span style=\"background-color: transparent; color: rgb(0, 0, 0);\">Les accompagnements approfondis ou spécialisés peuvent être conditionnés selon les programmes en cours ou les critères d’éligibilité.</span></p>', 'f9a16e49-d975-4d63-b201-5aee5888ac44', '3c4fbe39-dfa8-43c0-b7fd-bb946236543d', 0, 1, '2026-02-19 13:19:27', '2026-02-19 13:19:27');
