INSERT INTO `plantemplates` (`id`, `diagnosticmodule_id`, `diagnosticquestion_id`, `niveau`, `objectif`, `actionprioritaire`, `priorite`, `spotlight`, `etat`, `created_at`, `updated_at`) VALUES
(1, 115, 850, '1', 'Atteindre l\'excellence stratégique', '1. Formaliser une vision claire à 3-5 ans<br>2. Documenter le modèle économique complet<br>3. Définir les indicateurs de succès clés', 1, 0, 1, '2026-03-03 13:51:04', '2026-03-03 13:51:04'),
(2, 115, 850, '2', 'Atteindre l\'excellence stratégique', '1. Structurer la vision stratégique formelle<br>2. Définir les indicateurs de succès clés', 2, 0, 1, '2026-03-03 13:51:04', '2026-03-03 13:51:04'),
(3, 115, 850, '3', 'Atteindre l\'excellence stratégique', '1. Documenter le business model complet', 3, 0, 1, '2026-03-03 13:51:04', '2026-03-03 13:51:04'),
(4, 115, 850, '4', 'Excellence stratégique atteinte', 'Félicitations ! Vous avez une vision stratégique précise, chiffrée et cohérente.', 4, 0, 1, '2026-03-03 13:51:04', '2026-03-03 13:51:04'),
(5, 115, 851, '1', 'Atteindre la maîtrise stratégique', '1. Apprendre à dire non poliment mais fermement<br>2. Créer des critères de sélection clairs<br>3. Identifier les opportunités non alignées', 1, 0, 1, '2026-03-03 13:51:04', '2026-03-03 13:51:04'),
(6, 115, 851, '2', 'Atteindre la maîtrise stratégique', '1. Développer la discipline stratégique<br>2. Créer des critères de sélection clairs', 2, 0, 1, '2026-03-03 13:51:04', '2026-03-03 13:51:04'),
(7, 115, 851, '3', 'Atteindre la maîtrise stratégique', '1. Optimiser l\'allocation des ressources', 3, 0, 1, '2026-03-03 13:51:04', '2026-03-03 13:51:04'),
(8, 115, 851, '4', 'Maîtrise stratégique atteinte', 'Félicitations ! Vous maîtrisez parfaitement l\'art de renoncer stratégiquement.', 4, 0, 1, '2026-03-03 13:51:04', '2026-03-03 13:51:04'),
(13, 115, 853, '1', 'Atteindre l\'anticipation marché', '1. Mettre en place un suivi mensuel des ventes et marges<br>2. Créer un tableau de bord des indicateurs clés<br>3. Identifier les signaux faibles du marché', 1, 0, 1, '2026-03-03 13:51:04', '2026-03-03 13:51:04'),
(14, 115, 853, '2', 'Atteindre l\'anticipation marché', '1. Mettre en place une veille concurrentielle active<br>2. Créer un système d\'alerte sur les changements', 2, 0, 1, '2026-03-03 13:51:04', '2026-03-03 13:51:04'),
(15, 115, 853, '3', 'Atteindre l\'anticipation marché', '1. Développer une analyse prospective des tendances', 3, 0, 1, '2026-03-03 13:51:04', '2026-03-03 13:51:04'),
(16, 115, 853, '4', 'Excellence en anticipation marché', 'Félicitations ! Vous anticipez parfaitement les évolutions du marché.', 4, 0, 1, '2026-03-03 13:51:04', '2026-03-03 13:51:04'),
(21, 115, 855, '1', 'Atteindre la transmission efficace', '1. Formaliser la vision stratégique par écrit<br>2. Organiser une réunion de présentation de la vision<br>3. Créer des supports visuels de la vision', 1, 0, 1, '2026-03-03 13:51:04', '2026-03-03 13:51:04'),
(22, 115, 855, '2', 'Atteindre la transmission efficace', '1. Lier les objectifs court terme à la vision long terme<br>2. Former les équipes à communiquer la vision', 2, 0, 1, '2026-03-03 13:51:04', '2026-03-03 13:51:04'),
