INSERT INTO `services` (`id`, `titre`, `resume`, `description`, `langue_id`, `vignette`, `pays_id`, `spotlight`, `etat`, `created_at`, `updated_at`) VALUES
(1, 'Diagnostic 360 degré', 'Un outil digital d’évaluation multi-blocs permettant d’analyser objectivement le niveau de structuration de l’entreprise.', NULL, 'f9a16e49-d975-4d63-b201-5aee5888ac44', 'services/2026/02/19/6996fc6fb5d0a_1652a2e42d.jpg.jpeg', '3c4fbe39-dfa8-43c0-b7fd-bb946236543d', 0, 1, '2025-07-21 18:02:50', '2026-02-19 12:05:03'),
(2, 'Scoring et Classification', 'Attribution automatique d’un niveau de maturité (Pépite, Émergent, Élite) sur la base de critères mesurables.', NULL, 'f9a16e49-d975-4d63-b201-5aee5888ac44', 'services/2026/02/19/6996fcafda1c0_7789770de0.jpg.jpeg', '3c4fbe39-dfa8-43c0-b7fd-bb946236543d', 0, 1, '2025-07-21 18:03:20', '2026-02-19 12:06:07'),
(3, 'Génération du PAP', 'Production instantanée d’un plan d’accompagnement personnalisé après diagnostic.', NULL, 'f9a16e49-d975-4d63-b201-5aee5888ac44', 'services/2026/02/19/6996fd01e4b75_b1b626f7a7.jpg.jpeg', '3c4fbe39-dfa8-43c0-b7fd-bb946236543d', 0, 1, '2025-07-21 18:04:04', '2026-02-19 12:07:30'),
(4, 'Système de mise en relation', 'Connexion structurée avec consultants, agences, coachs et conseillers agréés CJES.', NULL, 'f9a16e49-d975-4d63-b201-5aee5888ac44', 'services/2026/02/19/6996fd2b5cd86_c37a0353bd.jpg.jpeg', '3c4fbe39-dfa8-43c0-b7fd-bb946236543d', 0, 1, '2025-07-21 18:04:33', '2026-02-19 12:08:11'),
(5, 'Intégration avec CJES ACADEMY', 'Recommandation automatique de modules de formation adaptés aux besoins identifiés.', NULL, 'f9a16e49-d975-4d63-b201-5aee5888ac44', 'services/2026/02/19/6996fd5bca4c9_f8f3473a24.jpg.jpeg', '3c4fbe39-dfa8-43c0-b7fd-bb946236543d', 0, 1, '2025-07-21 18:05:04', '2026-02-19 12:08:59'),
(6, 'Badges digitaux de capacité', 'Certification numérique attestant du niveau réel de structuration de l’entreprise.', NULL, 'f9a16e49-d975-4d63-b201-5aee5888ac44', 'services/2026/02/19/6996fd8925882_09880a70e1.jpg.jpeg', '3c4fbe39-dfa8-43c0-b7fd-bb946236543d', 0, 1, '2025-07-21 18:05:35', '2026-02-19 12:09:45');
