(1, 'Incubons l’avenir ensemble.', 'Accédez à un accompagnement structuré, intelligent et sans barrières.', NULL, 'f9a16e49-d975-4d63-b201-5aee5888ac44', 'sliders/2026/02/27/69a169e2e4980_nouveau_projet.jpg', 1, NULL, '3c4fbe39-dfa8-43c0-b7fd-bb946236543d', 0, 1, '2025-07-21 17:38:24', '2026-02-27 09:54:42'),
(3, 'Appel à Manifestation d\'Intérêt', 'Recrutement de prestataires', '<p><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">La CJES Togo recrute des partenaires qualifiés (agences, cabinets, consultants, experts, coachs, mentors et encadreurs) pour accompagner la structuration des jeunes entreprises togolaises.</span></p>', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 'sliders/2026/02/27/69a1698e72080_nouveau_projet__1_.jpg', 1, 'https://lnkd.in/dGagGPcp', '3c4fbe39-dfa8-43c0-b7fd-bb946236543d', 0, 1, '2026-02-26 15:47:33', '2026-02-27 11:11:39');
