INSERT INTO `temoignages` (`id`, `nom`, `profil`, `commentaire`, `langue_id`, `vignette`, `pays_id`, `spotlight`, `etat`, `created_at`, `updated_at`) VALUES
(1, '\"', 'Entrepreneure, Lomé', 'Grâce à e-CIJES, nous avons pu structurer notre entreprise et accéder à un premier financement.', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 'temoignages/2026/02/27/69a16ba79e1e9_oldtemoignage.jpg', '3c4fbe39-dfa8-43c0-b7fd-bb946236543d', 0, 1, '2025-07-02 22:53:22', '2026-02-27 10:02:52'),
(2, '\"', 'Start-uppeur, Kara', 'Le diagnostic m’a ouvert les yeux sur ce que je devais prioriser.', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 'temoignages/2026/02/27/69a170769cadb_oldtemoignage__2_.jpg', '3c4fbe39-dfa8-43c0-b7fd-bb946236543d', 0, 1, '2026-02-19 12:15:03', '2026-02-27 10:22:46'),
(3, '\"', 'Dirigeante PME, Sokodé', 'Les coachs m’ont aidé à clarifier ma vision et mon positionnement.', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 'temoignages/2026/02/27/69a16dd8a4303_oldtemoignage__1_.jpg', '3c4fbe39-dfa8-43c0-b7fd-bb946236543d', 0, 1, '2026-02-19 12:16:04', '2026-02-27 10:11:36');
