(47, 50, 'Axe d’amélioration – Bloc 3 – Juridique', 'Renforcer la conformité juridique et sécuriser les engagements contractuels pour limiter les risques.', 0, 1, '2026-02-12 14:08:13', '2026-02-12 14:08:13'),
(48, 51, 'Axe d’amélioration – Bloc 4 – Ressources humaines', 'Structurer la gestion des ressources humaines et formaliser les procédures internes pour améliorer la performance collective.', 0, 1, '2026-02-12 14:08:13', '2026-02-12 14:08:13'),
(49, 52, 'Axe d’amélioration – Bloc 5 – Marketing', 'Optimiser la stratégie marketing et affiner le positionnement pour accroître l’attractivité et la compétitivité.', 0, 1, '2026-02-12 14:08:13', '2026-02-12 14:08:13'),
(50, 53, 'Axe d’amélioration – Bloc 6 – Communication', 'Renforcer la cohérence des actions de communication afin d’améliorer la visibilité et la crédibilité.', 0, 1, '2026-02-12 14:08:13', '2026-02-12 14:08:13'),
(51, 54, 'Axe d’amélioration – Bloc 7 – Commercial', 'Professionnaliser l’organisation commerciale et améliorer le suivi des prospects et clients.', 0, 1, '2026-02-12 14:08:13', '2026-02-12 14:08:13'),
(52, 55, 'Axe d’amélioration – Bloc 8 – Opérations', 'Optimiser les processus opérationnels pour améliorer la qualité, la productivité et la maîtrise des délais.', 0, 1, '2026-02-12 14:08:13', '2026-02-12 14:08:13'),
(53, 56, 'Axe d’amélioration – Bloc 9 – Digital', 'Développer l’usage stratégique des outils digitaux pour renforcer la performance et l’efficacité interne.', 0, 1, '2026-02-12 14:08:13', '2026-02-12 14:08:13'),
(54, 57, 'Axe d’amélioration – Bloc 10 – Administration', 'Structurer davantage la gestion administrative pour assurer un pilotage plus rigoureux et organisé.', 0, 1, '2026-02-12 14:08:13', '2026-02-12 14:08:13'),
(55, 115, 'FONCTION 1 : Pensée stratégique & Intelligence économique', 'Cap – Anticipation – Alignement – Discernement long terme<br>Compétences développées :<br>Projection à moyen et long terme<br>Discipline d\'allocation stratégique des ressources<br>Cohérence décisionnelle<br>Anticipation des évolutions environnementales<br>Maturité face au risque<br>Leadership stratégique aligné<br>Transformation centrale : Passer de la gestion permanente de l\'urgence à la construction d\'une trajectoire structurée.', 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(56, 116, 'FONCTION 2 : Influence relationnelle & Mobilisation stratégique', 'Clarté – Conviction – Alliances – Impact<br>Compétences développées :<br>Clarté communicationnelle<br>Écoute stratégique<br>Influence crédible<br>Conduite du changement<br>Construction d\'alliances<br>Capacité de mobilisation durable<br>Transformation centrale : Passer d\'entrepreneur isolé à leader mobilisateur.', 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(57, 117, 'FONCTION 3 : Leadership d\'équipe & Développement des talents', 'Responsabilisation – Transmission – Autonomie<br>Compétences développées :<br>Lâcher-prise constructif<br>Exigence juste et équilibrée<br>Empowerment<br>Feedback structurant<br>Création d\'une culture d\'équipe<br>Construction d\'autonomie organisationnelle<br>Transformation centrale : Passer de contrôleur opérationnel à développeur de leaders.', 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(58, 118, 'FONCTION 4 : Maîtrise émotionnelle & Gestion des tensions', 'Régulation – Stabilité – Résilience<br>Compétences développées :<br>Conscience émotionnelle<br>Régulation sous pression<br>Résilience stratégique<br>Gestion mature des conflits<br>Stabilité face à l\'incertitude<br>Autorité émotionnelle calme<br>Transformation centrale : Passer d\'une posture réactive à un ancrage émotionnel stable.', 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(59, 119, 'FONCTION 5 : Décision & Discernement analytique', 'Méthode – Courage – Responsabilité<br>Compétences développées :<br>Maîtrise de l\'impulsivité<br>Structuration du raisonnement<br>Lecture équilibrée du risque<br>Décision sous pression<br>Responsabilité post-décision<br>Construction d\'une méthode décisionnelle personnelle<br>Transformation centrale : Passer de l\'intuition non maîtrisée au discernement structuré.', 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(60, 120, 'FONCTION 6 : Adaptabilité & Conduite du changement', 'Anticipation – Ajustement – Leadership de transition<br>Compétences développées :<br>Veille proactive<br>Analyse avant action<br>Conduite structurée du changement<br>Gestion de la résistance<br>Pilotage discipliné<br>Repositionnement stratégique en période de crise<br>Transformation centrale : Passer de la réaction subie au pilotage adaptatif.', 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(61, 121, 'FONCTION 7 : Orientation client & Création de valeur', 'Posture marché – Écoute – Différenciation – Relation durable<br>Compétences développées :<br>Écoute stratégique du besoin réel<br>Positionnement assumé<br>Maturité tarifaire<br>Analyse des pertes clients<br>Discipline de fidélisation<br>Lecture proactive des opportunités marché<br>Transformation centrale : Passer de producteur centré sur soi à créateur de valeur stratégique.', 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(62, 122, 'FONCTION 8 : Initiative & Responsabilité', 'Agir – Assumer – Anticiper – Transformer<br>Compétences développées :<br>Réactivité proactive<br>Locus de contrôle interne<br>Initiative autonome<br>Structuration des opportunités<br>Culture d\'anticipation des risques<br>Mentalité transformationnelle<br>Transformation centrale : Passer de la justification à la responsabilité mature.', 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(63, 123, 'FONCTION 9 : Créativité & Innovation pragmatique', 'Solution – Adaptation – Expérimentation – Simplification<br>Compétences développées :<br>Analyse des causes racines<br>Ingéniosité sous contrainte<br>Discipline d\'expérimentation<br>Remise en question constructive<br>Culture d\'amélioration continue<br>Simplification stratégique<br>Transformation centrale : Passer de la réaction ponctuelle à l\'innovation structurée.', 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(64, 124, 'FONCTION 10 : Intégrité & Discipline personnelle', 'Rigueur – Cohérence – Fiabilité – Exemplarité<br>Compétences développées :<br>Maîtrise face au capital<br>Fiabilité dans les engagements<br>Intégrité autonome<br>Exemplarité comportementale<br>Discipline stratégique du temps<br>Leadership de responsabilité<br>Transformation centrale : Passer de l\'opportunisme court terme à la crédibilité durable.', 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(65, 125, 'FONCTION 1 : STRATÉGIE', 'Structurer et piloter la trajectoire<br>Le dirigeant sait et/ou sait faire faire :<br>Clarifier le modèle économique (Business Model)<br>Définir des objectifs stratégiques priorisés<br>Traduire la vision en feuille de route opérationnelle<br>Allouer les ressources selon les priorités<br>Définir des KPI stratégiques<br>Organiser des revues périodiques<br>Savoir-faire-faire : Aligner les équipes sur un cap clair et éviter la dispersion.', 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(66, 126, 'FONCTION 2 : FINANCE', 'Piloter la performance financière<br>Le dirigeant sait et/ou sait faire faire :<br>Lire et interpréter bilan et compte de résultat<br>Analyser marges, structure de coûts et seuil de rentabilité<br>Piloter le cash-flow et le besoin en fonds de roulement<br>Anticiper les tensions de trésorerie<br>Arbitrer entre distribution et réinvestissement<br>Utiliser l\'argent des autres (les banques) pour accélérer son entreprise<br>Savoir-faire-faire : Exiger des reportings fiables et prendre des décisions fondées sur les chiffres.', 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(67, 127, 'FONCTION 3 : JURIDIQUE', 'Sécuriser l\'entreprise<br>Le dirigeant sait et/ou sait faire faire :<br>Comprendre les obligations contractuelles (fournisseurs, clients, employés, contrats, baux commerciaux, etc.)<br>Superviser la conformité fiscale et sociale<br>Identifier et prévenir les risques juridiques majeurs<br>Sécuriser les partenariats stratégiques<br>Prévenir les conflits d\'intérêts<br>Formaliser les décisions sensibles<br>Diversifier les sources de revenus et de partenaires<br>Savoir-faire-faire : Mettre en place des règles internes claires et traçables.', 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(68, 128, 'FONCTION 4 : RESSOURCES HUMAINES', 'Structurer et développer le capital humain<br>Le dirigeant sait et/ou sait faire faire :<br>Définir les besoins en compétences<br>Recruter de manière structurée<br>Clarifier rôles et responsabilités<br>Fixer des objectifs mesurables<br>Mettre en place un système d\'évaluation<br>Déléguer avec contrôle<br>Gérer les performances insuffisantes<br>Savoir-faire-faire : Créer une organisation responsable et performante.', 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(69, 129, 'FONCTION 5 : MARKETING', 'Construire un positionnement différenciant<br>Le dirigeant sait et/ou sait faire faire :<br>Analyser le marché et la concurrence<br>Segmenter sa clientèle<br>Définir une politique de prix cohérente<br>Structurer une politique de prix cohérente<br>Adapter l\'offre à l\'évolution des besoins<br>Savoir-faire-faire : Aligner produit, marché et stratégie de croissance.', 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(70, 130, 'FONCTION 6 : COMMUNICATION', 'Organiser les flux d\'information et l\'image<br>Le dirigeant sait et/ou sait faire faire :<br>Structurer la communication interne<br>Clarifier les consignes et priorités<br>Organiser les circuits d\'information<br>Superviser la communication externe<br>Gérer la communication en situation de crise<br>Savoir-faire-faire : Maintenir la cohérence entre discours et actions.', 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(71, 140, 'FONCTION 7 : COMMERCIAL', 'Structurer la génération de revenus<br>Le dirigeant sait et/ou sait faire faire :<br>Définir une stratégie commerciale claire<br>Structurer un tunnel de vente<br>Piloter un portefeuille clients<br>Mettre en place des objectifs commerciaux<br>Suivre les indicateurs de performance<br>Superviser les négociations stratégiques<br>Protéger la réputation de l\'entreprise<br>Gérer les impayés<br>Savoir-faire-faire : Installer un système commercial reproductible.', 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(72, 141, 'FONCTION 8 : OPÉRATIONS', 'Garantir la qualité et la fluidité<br>Le dirigeant sait et/ou sait faire faire :<br>Cartographier la chaîne de valeur<br>Optimiser les flux de production ou de service<br>Structurer les processus critiques<br>Mettre en place des standards (SOP)<br>Structurer la gestion fournisseurs<br>Analyser les marges et le seuil de rentabilité<br>Superviser la qualité<br>Réduire la dépendance au dirigeant<br>Savoir-faire-faire : Faire fonctionner l\'entreprise sans supervision constante.', 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(73, 142, 'FONCTION 9 : DIGITAL', 'Moderniser et sécuriser les systèmes<br>Le dirigeant sait et/ou sait faire faire :<br>Identifier les besoins numériques prioritaires<br>Arbitrer le choix des solutions structurantes adaptés (CRM, ERP, outils collaboratifs)<br>Piloter la digitalisation progressive<br>Identifier les gisements d\'automatisation pour libérer du temps humain<br>Gouverner la donnée pour en faire un actif stratégique d\'aide à la décision.<br>Savoir-faire-faire : Améliorer la productivité par le système.', 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(74, 143, 'FONCTION 10 : ADMINISTRATION', 'Organiser le support et sécuriser la continuité<br>Le dirigeant sait et/ou sait faire faire :<br>Structurer le back-office<br>Mettre en place un système d\'archivage fiable<br>Organiser la logistique interne<br>Superviser les obligations administratives<br>Mettre en place un plan de continuité d\'activité<br>Identifier les dépendances critiques<br>Analyser les risques majeurs<br>Savoir-faire-faire : Maintenir la stabilité organisationnelle en toutes circonstances.', 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25');

